    private val purchaseConsumeQueue = Channel<String>(capacity = Channel.BUFFERED)

    private val billingClient: BillingClient by lazy(LazyThreadSafetyMode.SYNCHRONIZED) {
        BillingClient.newBuilder(appContext)
            .enablePendingPurchases()
            .setListener(this)
            .build()
    }

    init {
        ProcessLifecycleOwner.get().lifecycle.addObserver(object : DefaultLifecycleObserver {
            override fun onStart(owner: LifecycleOwner) {
                connectBillingIfNeeded()
            }
        })
        scope.launch {
            for (token in purchaseAckQueue) {
                acknowledgePurchaseInternal(token)
            }
        }
        scope.launch {
            for (token in purchaseConsumeQueue) {
                consumePurchaseInternal(token)
            }
        }
    }

    fun connectBillingIfNeeded() {
        if (billingClient.isReady) return
        _state.value = PaymentState.Connecting
        billingClient.startConnection(this)
    }

    fun disconnectBilling() {
        runCatching { billingClient.endConnection() }
        _state.value = PaymentState.Idle
        scope.launch { _events.emit(PaymentEvent.BillingReady(false)) }
    }

    override fun onBillingSetupFinished(result: BillingResult) {
        val ok = result.responseCode == BillingClient.BillingResponseCode.OK
        _state.value = PaymentState.Connected(billingSupported = ok)
        scope.launch {
            if (ok) _events.emit(PaymentEvent.BillingReady(true))
            else _events.emit(PaymentEvent.BillingError(result.responseCode, result.debugMessage))
        }
    }

    override fun onBillingServiceDisconnected() {
        _state.value = PaymentState.Failed("Billing disconnected")
        scope.launch { _events.emit(PaymentEvent.BillingReady(false)) }
    }

    override fun onPurchasesUpdated(result: BillingResult, purchases: MutableList<Purchase>?) {
        scope.launch {
            if (result.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
                _events.emit(PaymentEvent.BillingPurchaseUpdate(purchases))
            } else if (result.responseCode != BillingClient.BillingResponseCode.USER_CANCELED) {
                _events.emit(PaymentEvent.BillingError(result.responseCode, result.debugMessage))
            }
        }
    }

    suspend fun queryProductDetails(items: List<PurchaseSku>): List<ProductDetails> {
        connectBillingIfNeeded()
        if (!billingClient.isReady) return emptyList()

        val products = items.map {
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(it.productId)
                .setProductType(it.productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder().setProductList(products).build()
        val (billingResult, productDetailsList) = suspendCancellableCoroutine { cont ->
            billingClient.queryProductDetailsAsync(params) { br, list ->
                if (cont.isActive) cont.resume(br to list)
            }
        }

        return if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            scope.launch { _events.emit(PaymentEvent.BillingProducts(productDetailsList)) }
            productDetailsList
        } else {
            scope.launch { _events.emit(PaymentEvent.BillingError(billingResult.responseCode, billingResult.debugMessage)) }
            emptyList()
        }
    }

    fun launchPurchaseFlow(
        activity: Activity,
        productDetails: ProductDetails,
        offerToken: String? = null,
        obfuscatedAccountId: String? = null,
        obfuscatedProfileId: String? = null
