            .build()

        val params = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productParams)).apply {
                if (!obfuscatedAccountId.isNullOrBlank()) setObfuscatedAccountId(obfuscatedAccountId)
                if (!obfuscatedProfileId.isNullOrBlank()) setObfuscatedProfileId(obfuscatedProfileId)
            }
            .build()

