        val subs = queryPurchases(BillingClient.ProductType.SUBS)
        return inapp + subs
    }

    private suspend fun queryPurchases(@BillingClient.ProductType productType: String): List<Purchase> {
        val params = QueryPurchasesParams.newBuilder().setProductType(productType).build()
        val (br, list) = suspendCancellableCoroutine { cont ->
            billingClient.queryPurchasesAsync(params) { billingResult, purchases ->
                if (cont.isActive) cont.resume(billingResult to purchases)
            }
        }
        if (br.responseCode != BillingClient.BillingResponseCode.OK) {
            scope.launch { _events.emit(PaymentEvent.BillingError(br.responseCode, br.debugMessage)) }
            return emptyList()
        }
        return list
    }

    fun enqueueAcknowledge(purchaseToken: String) {
        purchaseAckQueue.trySend(purchaseToken)
    }

    fun enqueueConsume(purchaseToken: String) {
        purchaseConsumeQueue.trySend(purchaseToken)
    }

    suspend fun acknowledgePurchase(purchaseToken: String) {
        acknowledgePurchaseInternal(purchaseToken)
    }

    suspend fun consumePurchase(purchaseToken: String) {
        consumePurchaseInternal(purchaseToken)
    }

    private suspend fun acknowledgePurchaseInternal(purchaseToken: String) {
        connectBillingIfNeeded()
        if (!billingClient.isReady) return
        val params = AcknowledgePurchaseParams.newBuilder().setPurchaseToken(purchaseToken).build()
        val br = suspendCancellableCoroutine { cont ->
            billingClient.acknowledgePurchase(params) { billingResult ->
                if (cont.isActive) cont.resume(billingResult)
            }
        }
        if (br.responseCode == BillingClient.BillingResponseCode.OK) {
            _events.emit(PaymentEvent.BillingPurchaseAcknowledged(purchaseToken))
        } else {
            _events.emit(PaymentEvent.BillingError(br.responseCode, br.debugMessage))
        }
    }

    private suspend fun consumePurchaseInternal(purchaseToken: String) {
        connectBillingIfNeeded()
        if (!billingClient.isReady) return
        val params = ConsumeParams.newBuilder().setPurchaseToken(purchaseToken).build()
        val (br, outToken) = suspendCancellableCoroutine { cont ->
            billingClient.consumeAsync(params) { billingResult, token ->
                if (cont.isActive) cont.resume(billingResult to token)
            }
        }
        if (br.responseCode == BillingClient.BillingResponseCode.OK) {
            _events.emit(PaymentEvent.BillingPurchaseConsumed(outToken))
        } else {
            _events.emit(PaymentEvent.BillingError(br.responseCode, br.debugMessage))
        }
    }

    suspend fun submitWalletTransaction(request: WalletTransactionRequest): WalletTransactionResult {
        val aad = (request.idempotencyKey + "|" + request.amount.currency).toByteArray(Charsets.UTF_8)
        val payloadJson = buildWalletPayloadJson(request)

        SensitiveBuffer(payloadJson.toByteArray(Charsets.UTF_8)).use { buf ->
            val encrypted = crypto.encrypt(buf.bytesCopy(), aad)
            buf.wipe()

            val encB64 = Base64Compat.encodeToString(encrypted, Base64Compat.NO_WRAP)
            val deviceInfo = deviceInfoMap()

            return try {
                val result = walletApi.submitTransaction(
                    WalletTransactionRequestEncrypted(
                        idempotencyKey = request.idempotencyKey,
                        payload = encB64,
                        keyId = crypto.keyId(),
                        deviceInfo = deviceInfo
                    )
                )
                _events.emit(PaymentEvent.WalletTransaction(result))
                result
            } catch (t: Throwable) {
                _events.emit(PaymentEvent.WalletError("Wallet transaction failed", t))
                throw t
            }
        }
    }

    private fun buildWalletPayloadJson(request: WalletTransactionRequest): String {
        fun esc(s: String): String = s.replace("\\", "\\\\").replace("\"", "\\\"")
        fun mapToJson(m: Map<String, String>): String =
            m.entries.joinToString(prefix = "{", postfix = "}") { "\"${esc(it.key)}\":\"${esc(it.value)}\"" }

        val from = request.fromWalletToken?.value
        val to = request.toWalletToken?.value

        return buildString {
            append("{")
            append("\"amountMinor\":").append(request.amount.amountMinor).append(",")
            append("\"currency\":\"").append(esc(request.amount.currency)).append("\",")
            append("\"fromToken\":").append(if (from != null) "\"${esc(from)}\"" else "null").append(",")
            append("\"toToken\":").append(if (to != null) "\"${esc(to)}\"" else "null").append(",")
            append("\"metadata\":").append(mapToJson(request.metadata))
            append("}")
        }
    }

    private fun deviceInfoMap(): Map<String, String> {
        val manufacturer = Build.MANUFACTURER ?: "unknown"
        val model = Build.MODEL ?: "unknown"
        val sdk = Build.VERSION.SDK_INT.toString()
        val release = Build.VERSION.RELEASE ?: "unknown"
        val abi = Build.SUPPORTED_ABIS?.firstOrNull() ?: (Build.CPU_ABI ?: "unknown")
        return linkedMapOf(
            "manufacturer" to manufacturer,
            "model" to model,
            "sdkInt" to sdk,
            "release" to release,
            "abi" to abi
        )
    }
}

@Keep
object Base64Compat {
    const val NO_WRAP: Int = 2

    fun encodeToString(input: ByteArray, flags: Int): String {
        return try {
            android.util.Base64.encodeToString(input, flags)
        } catch (_: Throwable) {
            java.util.Base64.getEncoder().encodeToString(input)
        }
    }

    fun decode(input: String, flags: Int): ByteArray {
        return try {
            android.util.Base64.decode(input, flags)
        } catch (_: Throwable) {
            java.util.Base64.getDecoder().decode(input)
        }
    }
}

